'use client'

import { useState, useEffect } from 'react'
import { createBrowserClient } from '@supabase/ssr'
import { useRouter } from 'next/navigation'

// ─── Supabase direto, sem depender de @/lib ──────────────────────
function getSupabase() {
  return createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
  )
}

type Panel = 'login' | 'register' | 'forgot'

function translateError(msg: string): string {
  const m = msg.toLowerCase()
  if (m.includes('invalid login credentials') || m.includes('invalid credentials'))
    return 'E-mail ou senha incorretos.'
  if (m.includes('email not confirmed'))
    return 'Confirme seu e-mail antes de entrar. Verifique sua caixa de entrada.'
  if (m.includes('user already registered') || m.includes('already registered'))
    return 'Este e-mail já possui uma conta. Faça login.'
  if (m.includes('password should be at least'))
    return 'A senha deve ter pelo menos 8 caracteres.'
  if (m.includes('unable to validate email') || m.includes('invalid email'))
    return 'E-mail inválido. Verifique e tente novamente.'
  if (m.includes('rate limit') || m.includes('too many requests'))
    return 'Muitas tentativas. Aguarde alguns minutos.'
  if (m.includes('signup is disabled'))
    return 'Cadastros temporariamente desabilitados.'
  return msg
}

const LOGO = 'data:image/jpeg;base64,'

export default function AuthPage() {
  const router = useRouter()
  const [panel, setPanel]               = useState<Panel>('login')
  const [globalLoading, setGlobalLoading] = useState(true)
  const [loadingTxt, setLoadingTxt]     = useState('Verificando sessão...')
  const [btnLoading, setBtnLoading]     = useState(false)
  const [msgText, setMsgText]           = useState('')
  const [msgType, setMsgType]           = useState<'error'|'success'>('error')
  const [showMsg, setShowMsg]           = useState(false)
  const [showDash, setShowDash]         = useState(false)

  // Login fields
  const [loginEmail, setLoginEmail]   = useState('')
  const [loginPass, setLoginPass]     = useState('')
  const [showLP, setShowLP]           = useState(false)
  const [remember, setRemember]       = useState(false)

  // Register fields
  const [regName, setRegName]   = useState('')
  const [regEmail, setRegEmail] = useState('')
  const [regPass, setRegPass]   = useState('')
  const [showRP, setShowRP]     = useState(false)
  const [terms, setTerms]       = useState(false)
  const [strength, setStrength] = useState(0)

  // Forgot fields
  const [forgotEmail, setForgotEmail] = useState('')

  // ── Checar sessão ao montar ──────────────────────────────────────
  useEffect(() => {
    ;(async () => {
      try {
        const sb = getSupabase()
        const { data: { session } } = await sb.auth.getSession()
        if (session) {
          await doRedirect(sb, session.user.id, false)
        } else {
          setGlobalLoading(false)
        }
      } catch {
        setGlobalLoading(false)
      }
    })()
  }, [])

  async function doRedirect(sb: ReturnType<typeof getSupabase>, uid: string, isNew: boolean) {
    if (isNew) { router.push('/onboarding'); return }
    try {
      const { data } = await sb.from('profiles')
        .select('onboarding_completed').eq('id', uid).single()
      router.push(data?.onboarding_completed ? '/dashboard' : '/onboarding')
    } catch {
      router.push('/onboarding')
    }
  }

  function msg(text: string, type: 'error'|'success' = 'error') {
    setMsgText(text); setMsgType(type); setShowMsg(true)
  }
  function clearMsg() { setShowMsg(false) }

  function switchTab(t: Panel) { setPanel(t); clearMsg(); setShowDash(false) }

  function calcStrength(v: string) {
    let s = 0
    if (v.length >= 8) s++
    if (/[A-Z]/.test(v)) s++
    if (/[0-9]/.test(v)) s++
    if (/[^A-Za-z0-9]/.test(v)) s++
    setStrength(s)
  }

  // ── Google OAuth ──────────────────────────────────────────────────
  async function handleGoogle() {
    clearMsg(); setBtnLoading(true)
    try {
      const sb = getSupabase()
      const { error } = await sb.auth.signInWithOAuth({
        provider: 'google',
        options: { redirectTo: `${window.location.origin}/auth/callback` },
      })
      if (error) { msg(translateError(error.message)); setBtnLoading(false) }
      // se ok → redireciona para Google, não precisa fazer nada aqui
    } catch (e: any) {
      msg('Erro ao conectar com Google.'); setBtnLoading(false)
    }
  }

  // ── Login ─────────────────────────────────────────────────────────
  async function handleLogin() {
    clearMsg()
    if (!loginEmail || !loginPass) { msg('Preencha e-mail e senha.'); return }
    setBtnLoading(true)
    try {
      const sb = getSupabase()
      const { data, error } = await sb.auth.signInWithPassword({
        email: loginEmail, password: loginPass,
      })
      if (error) { msg(translateError(error.message)); setBtnLoading(false); return }
      msg('Login realizado! Redirecionando...', 'success')
      setShowDash(true)
      setLoadingTxt('Carregando seu dashboard...')
      setGlobalLoading(true)
      await doRedirect(sb, data.user.id, false)
    } catch (e: any) {
      msg('Erro inesperado. Tente novamente.'); setBtnLoading(false)
    }
  }

  // ── Cadastro ──────────────────────────────────────────────────────
  async function handleRegister() {
    clearMsg()
    if (!regName || !regEmail || !regPass) { msg('Preencha todos os campos.'); return }
    if (regPass.length < 8) { msg('A senha deve ter pelo menos 8 caracteres.'); return }
    if (!terms) { msg('Aceite os termos para continuar.'); return }
    setBtnLoading(true)
    try {
      const sb = getSupabase()
      const { data, error } = await sb.auth.signUp({
        email: regEmail, password: regPass,
        options: {
          data: { name: regName },
          emailRedirectTo: `${window.location.origin}/auth/callback`,
        },
      })
      if (error) { msg(translateError(error.message)); setBtnLoading(false); return }
      if (data.session) {
        setLoadingTxt('Preparando seu onboarding...')
        setGlobalLoading(true)
        await doRedirect(sb, data.user!.id, true)
        return
      }
      msg('Conta criada! Verifique seu e-mail para confirmar.', 'success')
      setBtnLoading(false)
    } catch (e: any) {
      msg('Erro inesperado. Tente novamente.'); setBtnLoading(false)
    }
  }

  // ── Esqueci senha ─────────────────────────────────────────────────
  async function handleForgot() {
    clearMsg()
    if (!forgotEmail) { msg('Digite seu e-mail.'); return }
    setBtnLoading(true)
    try {
      const sb = getSupabase()
      const { error } = await sb.auth.resetPasswordForEmail(forgotEmail, {
        redirectTo: `${window.location.origin}/reset-password`,
      })
      if (error) { msg(translateError(error.message)); setBtnLoading(false); return }
      msg('Link enviado! Verifique sua caixa de entrada (e o spam).', 'success')
      setBtnLoading(false)
    } catch (e: any) {
      msg('Erro inesperado. Tente novamente.'); setBtnLoading(false)
    }
  }

  // ── Enter key ─────────────────────────────────────────────────────
  function onKeyDown(e: React.KeyboardEvent) {
    if (e.key !== 'Enter') return
    if (panel === 'login') handleLogin()
    else if (panel === 'register') handleRegister()
    else handleForgot()
  }

  const sColors = ['', '#ff4444', '#f59e0b', '#00d68f', '#00d68f']
  const sLabels = ['', 'Fraca', 'Média', 'Boa', 'Forte']

  // ── Loading fullscreen ────────────────────────────────────────────
  if (globalLoading) return (
    <div style={{
      position:'fixed',inset:0,background:'#030508',
      display:'flex',flexDirection:'column',alignItems:'center',
      justifyContent:'center',gap:16,zIndex:9999
    }}>
      <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
      <div style={{
        width:36,height:36,borderRadius:'50%',
        border:'3px solid rgba(26,108,255,.2)',borderTopColor:'#1a6cff',
        animation:'spin .8s linear infinite'
      }}/>
      <p style={{color:'rgba(255,255,255,.5)',fontSize:13}}>{loadingTxt}</p>
    </div>
  )

  // ── Page ──────────────────────────────────────────────────────────
  return (
    <div style={{
      background:'#030508',color:'#fff',minHeight:'100svh',
      fontFamily:'ui-sans-serif,system-ui,sans-serif',
      display:'flex',flexDirection:'column',
      WebkitFontSmoothing:'antialiased' as any,
    }} onKeyDown={onKeyDown}>

      <style>{`
        @keyframes spin{to{transform:rotate(360deg)}}
        @keyframes cdup{from{opacity:0;transform:translateY(24px)}to{opacity:1;transform:translateY(0)}}
        @keyframes glow{0%,100%{opacity:.6}50%{opacity:1}}
        .mn-input{width:100%;padding:13px 13px 13px 42px;background:rgba(255,255,255,.05);
          border:1px solid rgba(255,255,255,.1);border-radius:12px;color:#fff;
          font-size:14px;font-family:inherit;outline:none;transition:border-color .2s,background .2s;
          -webkit-appearance:none;}
        .mn-input:focus{border-color:rgba(26,108,255,.6);background:rgba(26,108,255,.07);}
        .mn-input::placeholder{color:rgba(255,255,255,.22);}
        .mn-btn-primary{width:100%;padding:15px;background:#1a6cff;color:#fff;border:none;
          border-radius:12px;font-size:15px;font-weight:800;cursor:pointer;
          box-shadow:0 6px 32px rgba(26,108,255,.4);margin-bottom:18px;letter-spacing:.2px;
          transition:transform .15s,box-shadow .15s;}
        .mn-btn-primary:hover{transform:translateY(-2px);box-shadow:0 10px 48px rgba(26,108,255,.6);}
        .mn-btn-primary:active{transform:scale(.99);}
        .mn-btn-primary:disabled{opacity:.6;cursor:not-allowed;transform:none;}
        .mn-btn-google{width:100%;padding:13px 20px;border-radius:12px;
          border:1px solid rgba(255,255,255,.1);background:rgba(255,255,255,.04);
          color:rgba(255,255,255,.8);font-size:14px;font-weight:600;cursor:pointer;
          display:flex;align-items:center;justify-content:center;gap:11px;
          margin-bottom:22px;transition:background .2s,border-color .2s;}
        .mn-btn-google:hover{background:rgba(255,255,255,.09);border-color:rgba(255,255,255,.2);color:#fff;}
        .mn-btn-ghost{width:100%;padding:13px;background:transparent;
          border:1px solid rgba(255,255,255,.09);border-radius:12px;
          color:rgba(255,255,255,.5);font-size:14px;font-weight:600;cursor:pointer;
          margin-top:10px;transition:border-color .2s,color .2s;}
        .mn-btn-ghost:hover{border-color:rgba(255,255,255,.2);color:#fff;}
        .mn-tab{flex:1;padding:10px;font-size:13px;font-weight:700;border:none;
          background:transparent;color:rgba(255,255,255,.5);cursor:pointer;
          border-radius:9px;transition:all .25s;}
        .mn-tab.active{color:#fff;background:#1a6cff;box-shadow:0 4px 20px rgba(26,108,255,.4);}
        .mn-nav-back{display:flex;align-items:center;gap:7px;font-size:13px;
          color:rgba(255,255,255,.5);text-decoration:none;padding:8px 16px;
          border:1px solid rgba(255,255,255,.09);border-radius:8px;
          transition:color .2s,border-color .2s,background .2s;}
        .mn-nav-back:hover{color:#fff;border-color:rgba(255,255,255,.2);background:rgba(255,255,255,.05);}
        .mn-footer-a{color:rgba(255,255,255,.4);text-decoration:none;transition:color .2s;}
        .mn-footer-a:hover{color:rgba(255,255,255,.7);}
        .mn-hint{font-size:11px;color:#4d94ff;font-weight:600;cursor:pointer;
          text-decoration:none;letter-spacing:0;text-transform:none;}
        .mn-hint:hover{color:#fff;}
        .mn-terms-a{color:#4d94ff;text-decoration:none;}
        .mn-dash-btn{width:100%;padding:15px;background:linear-gradient(135deg,#00d68f,#00b87a);
          color:#fff;border:none;border-radius:12px;font-size:15px;font-weight:800;cursor:pointer;
          display:flex;align-items:center;justify-content:center;gap:8px;
          box-shadow:0 6px 32px rgba(0,214,143,.3);margin-bottom:14px;}
        .mn-dash-btn:hover{transform:translateY(-2px);}
      `}</style>

      {/* Nav */}
      <nav style={{
        display:'flex',alignItems:'center',justifyContent:'space-between',
        padding:'18px 40px',borderBottom:'1px solid rgba(255,255,255,.08)',
        background:'rgba(3,5,8,.7)',backdropFilter:'blur(20px)',
        position:'relative',zIndex:200
      }}>
        <a href="/" style={{display:'flex',alignItems:'center',gap:10,fontSize:19,
          fontWeight:800,letterSpacing:-.5,textDecoration:'none',color:'#fff'}}>
          <img src={LOGO} alt="Monetax" style={{width:34,height:34,objectFit:'contain',
            filter:'drop-shadow(0 0 10px rgba(26,108,255,.5))'}} />
          Monetax
        </a>
        <a href="/" className="mn-nav-back">← Voltar ao site</a>
      </nav>

      {/* Glow */}
      <div style={{position:'fixed',top:'50%',left:'50%',transform:'translate(-50%,-50%)',
        width:700,height:700,borderRadius:'50%',pointerEvents:'none',zIndex:0,
        background:'radial-gradient(circle,rgba(26,108,255,.12) 0%,transparent 65%)',
        animation:'glow 7s ease-in-out infinite'}} />

      {/* Card */}
      <main style={{flex:1,display:'flex',alignItems:'center',justifyContent:'center',
        padding:'40px 20px 60px',position:'relative',zIndex:2}}>
        <div style={{width:'100%',maxWidth:460,background:'#0a1628',
          border:'1px solid rgba(255,255,255,.09)',
          borderTop:'1px solid rgba(255,255,255,.16)',
          borderRadius:24,overflow:'hidden',
          boxShadow:'0 40px 100px rgba(0,0,0,.6),0 0 60px rgba(26,108,255,.07)',
          animation:'cdup .6s ease both'}}>

          {/* Head */}
          <div style={{padding:'36px 36px 0',textAlign:'center'}}>
            <div style={{width:72,height:72,borderRadius:20,
              background:'rgba(26,108,255,.09)',border:'1px solid rgba(26,108,255,.3)',
              display:'flex',alignItems:'center',justifyContent:'center',
              margin:'0 auto 18px',padding:6,
              boxShadow:'0 0 24px rgba(26,108,255,.2)'}}>
              <img src={LOGO} alt="Monetax" style={{width:'100%',height:'100%',objectFit:'contain'}} />
            </div>
            <div style={{display:'inline-flex',alignItems:'center',gap:6,
              fontSize:10,fontWeight:700,letterSpacing:1.5,textTransform:'uppercase',
              color:'#00d68f',border:'1px solid rgba(0,214,143,.2)',
              background:'rgba(0,214,143,.07)',padding:'5px 13px',borderRadius:100,marginBottom:16}}>
              <span style={{width:5,height:5,background:'#00d68f',borderRadius:'50%',display:'inline-block'}} />
              CONEXÃO SEGURA
            </div>
            <h1 style={{fontSize:24,fontWeight:800,letterSpacing:-.6,marginBottom:6}}>
              Bem-vindo à <span style={{color:'#4d94ff'}}>Monetax</span>
            </h1>
            <p style={{fontSize:13,color:'rgba(255,255,255,.5)',marginBottom:28,lineHeight:1.6}}>
              Seu sistema de decisão financeira com IA.
            </p>
          </div>

          {/* Tabs */}
          <div style={{display:'flex',background:'rgba(255,255,255,.04)',
            border:'1px solid rgba(255,255,255,.08)',borderRadius:12,
            padding:4,margin:'0 36px 26px'}}>
            <button className={`mn-tab${panel==='login'?' active':''}`}
              onClick={() => switchTab('login')}>Entrar</button>
            <button className={`mn-tab${panel==='register'?' active':''}`}
              onClick={() => switchTab('register')}>⚡ Começar grátis</button>
          </div>

          {/* Body */}
          <div style={{padding:'0 36px 36px'}}>

            {/* Google */}
            <button className="mn-btn-google" onClick={handleGoogle} disabled={btnLoading}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none">
                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
              </svg>
              Continuar com Google
            </button>

            {/* Divider */}
            <div style={{display:'flex',alignItems:'center',gap:14,marginBottom:22}}>
              <div style={{flex:1,height:1,background:'rgba(255,255,255,.08)'}}/> 
              <span style={{fontSize:11,letterSpacing:1.5,textTransform:'uppercase',
                color:'rgba(255,255,255,.4)',whiteSpace:'nowrap'}}>ou use seu e-mail</span>
              <div style={{flex:1,height:1,background:'rgba(255,255,255,.08)'}}/> 
            </div>

            {/* Msg */}
            {showMsg && (
              <div style={{
                display:'flex',alignItems:'flex-start',gap:10,
                padding:'12px 14px',borderRadius:10,fontSize:13,lineHeight:1.5,marginBottom:16,
                ...(msgType==='success'
                  ? {background:'rgba(0,214,143,.07)',border:'1px solid rgba(0,214,143,.2)',color:'#80ffd4'}
                  : {background:'rgba(255,68,68,.07)',border:'1px solid rgba(255,68,68,.2)',color:'#ffaaaa'})
              }}>
                <span>{msgType==='success'?'✅':'⚠️'}</span>
                <span>{msgText}</span>
              </div>
            )}

            {/* ══ LOGIN ══ */}
            {panel==='login' && (
              <>
                {showDash && (
                  <button className="mn-dash-btn" onClick={() => router.push('/dashboard')}>
                    🚀 Ir para o meu dashboard
                  </button>
                )}

                {/* Email */}
                <div style={{marginBottom:16}}>
                  <div style={{fontSize:11,fontWeight:700,letterSpacing:1,
                    textTransform:'uppercase',color:'rgba(255,255,255,.5)',marginBottom:8}}>E-mail</div>
                  <div style={{position:'relative'}}>
                    <span style={{position:'absolute',left:14,top:'50%',transform:'translateY(-50%)',
                      fontSize:15,pointerEvents:'none',color:'rgba(255,255,255,.4)'}}>✉</span>
                    <input className="mn-input" type="email" placeholder="seu@email.com"
                      value={loginEmail} onChange={e => setLoginEmail(e.target.value)}
                      autoComplete="email" />
                  </div>
                </div>

                {/* Senha */}
                <div style={{marginBottom:8}}>
                  <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',
                    fontSize:11,fontWeight:700,letterSpacing:1,textTransform:'uppercase',
                    color:'rgba(255,255,255,.5)',marginBottom:8}}>
                    <span>Senha</span>
                    <a className="mn-hint" onClick={() => switchTab('forgot')}>Esqueci a senha</a>
                  </div>
                  <div style={{position:'relative'}}>
                    <span style={{position:'absolute',left:14,top:'50%',transform:'translateY(-50%)',
                      fontSize:15,pointerEvents:'none',color:'rgba(255,255,255,.4)'}}>🔑</span>
                    <input className="mn-input" type={showLP?'text':'password'} placeholder="••••••••"
                      value={loginPass} onChange={e => setLoginPass(e.target.value)}
                      autoComplete="current-password" />
                    <button onClick={() => setShowLP(v=>!v)}
                      style={{position:'absolute',right:12,top:'50%',transform:'translateY(-50%)',
                        background:'none',border:'none',cursor:'pointer',
                        color:'rgba(255,255,255,.4)',fontSize:15,padding:4,lineHeight:1}}>
                      {showLP?'🙈':'👁'}
                    </button>
                  </div>
                </div>

                {/* Lembrar */}
                <label style={{display:'flex',alignItems:'center',gap:9,cursor:'pointer',
                  userSelect:'none',marginBottom:22}}>
                  <input type="checkbox" checked={remember} onChange={e=>setRemember(e.target.checked)}
                    style={{width:15,height:15,accentColor:'#1a6cff',cursor:'pointer'}} />
                  <span style={{fontSize:13,color:'rgba(255,255,255,.5)'}}>Lembrar de mim</span>
                </label>

                <button className="mn-btn-primary" onClick={handleLogin} disabled={btnLoading}>
                  {btnLoading ? 'Entrando...' : 'Entrar na Monetax →'}
                </button>

                <p style={{fontSize:11,color:'rgba(255,255,255,.4)',textAlign:'center',lineHeight:1.7}}>
                  Ao entrar, você concorda com os{' '}
                  <a href="/termos" className="mn-terms-a">Termos de Uso</a> e a{' '}
                  <a href="/privacidade" className="mn-terms-a">Política de Privacidade</a>.
                </p>
              </>
            )}

            {/* ══ REGISTER ══ */}
            {panel==='register' && (
              <>
                {/* Nome */}
                <div style={{marginBottom:16}}>
                  <div style={{fontSize:11,fontWeight:700,letterSpacing:1,textTransform:'uppercase',
                    color:'rgba(255,255,255,.5)',marginBottom:8}}>Nome completo</div>
                  <div style={{position:'relative'}}>
                    <span style={{position:'absolute',left:14,top:'50%',transform:'translateY(-50%)',
                      fontSize:15,pointerEvents:'none',color:'rgba(255,255,255,.4)'}}>👤</span>
                    <input className="mn-input" type="text" placeholder="Seu nome"
                      value={regName} onChange={e=>setRegName(e.target.value)} autoComplete="name" />
                  </div>
                </div>
                {/* Email */}
                <div style={{marginBottom:16}}>
                  <div style={{fontSize:11,fontWeight:700,letterSpacing:1,textTransform:'uppercase',
                    color:'rgba(255,255,255,.5)',marginBottom:8}}>E-mail</div>
                  <div style={{position:'relative'}}>
                    <span style={{position:'absolute',left:14,top:'50%',transform:'translateY(-50%)',
                      fontSize:15,pointerEvents:'none',color:'rgba(255,255,255,.4)'}}>✉</span>
                    <input className="mn-input" type="email" placeholder="seu@email.com"
                      value={regEmail} onChange={e=>setRegEmail(e.target.value)} autoComplete="email" />
                  </div>
                </div>
                {/* Senha */}
                <div style={{marginBottom:16}}>
                  <div style={{fontSize:11,fontWeight:700,letterSpacing:1,textTransform:'uppercase',
                    color:'rgba(255,255,255,.5)',marginBottom:8}}>Senha</div>
                  <div style={{position:'relative'}}>
                    <span style={{position:'absolute',left:14,top:'50%',transform:'translateY(-50%)',
                      fontSize:15,pointerEvents:'none',color:'rgba(255,255,255,.4)'}}>🔑</span>
                    <input className="mn-input" type={showRP?'text':'password'}
                      placeholder="Mínimo 8 caracteres"
                      value={regPass} onChange={e=>{setRegPass(e.target.value);calcStrength(e.target.value)}}
                      autoComplete="new-password" />
                    <button onClick={()=>setShowRP(v=>!v)}
                      style={{position:'absolute',right:12,top:'50%',transform:'translateY(-50%)',
                        background:'none',border:'none',cursor:'pointer',
                        color:'rgba(255,255,255,.4)',fontSize:15,padding:4,lineHeight:1}}>
                      {showRP?'🙈':'👁'}
                    </button>
                  </div>
                  {regPass && (
                    <>
                      <div style={{display:'flex',gap:4,marginTop:8,height:3}}>
                        {[1,2,3,4].map(i=>(
                          <div key={i} style={{flex:1,height:'100%',borderRadius:2,
                            background:i<=strength?sColors[strength]:'rgba(255,255,255,.08)',
                            transition:'background .35s'}} />
                        ))}
                      </div>
                      <div style={{fontSize:10,textAlign:'right',marginTop:4,
                        color:sColors[strength]}}>{sLabels[strength]}</div>
                    </>
                  )}
                </div>
                {/* Termos */}
                <label style={{display:'flex',alignItems:'center',gap:9,cursor:'pointer',
                  userSelect:'none',marginBottom:22}}>
                  <input type="checkbox" checked={terms} onChange={e=>setTerms(e.target.checked)}
                    style={{width:15,height:15,accentColor:'#1a6cff',cursor:'pointer'}} />
                  <span style={{fontSize:13,color:'rgba(255,255,255,.5)'}}>
                    Concordo com os{' '}
                    <a href="/termos" className="mn-terms-a">Termos</a> e{' '}
                    <a href="/privacidade" className="mn-terms-a">Privacidade</a>
                  </span>
                </label>

                <button className="mn-btn-primary" onClick={handleRegister} disabled={btnLoading}>
                  {btnLoading ? 'Criando conta...' : 'Começar Grátis →'}
                </button>
                <p style={{fontSize:11,color:'rgba(255,255,255,.4)',textAlign:'center'}}>
                  Sem cartão de crédito. Cancele quando quiser.
                </p>
              </>
            )}

            {/* ══ FORGOT ══ */}
            {panel==='forgot' && (
              <>
                <p style={{fontSize:13,color:'rgba(255,255,255,.5)',lineHeight:1.7,marginBottom:20}}>
                  Digite seu e-mail e enviaremos um link para redefinir sua senha.
                </p>
                <div style={{marginBottom:16}}>
                  <div style={{fontSize:11,fontWeight:700,letterSpacing:1,textTransform:'uppercase',
                    color:'rgba(255,255,255,.5)',marginBottom:8}}>E-mail cadastrado</div>
                  <div style={{position:'relative'}}>
                    <span style={{position:'absolute',left:14,top:'50%',transform:'translateY(-50%)',
                      fontSize:15,pointerEvents:'none',color:'rgba(255,255,255,.4)'}}>✉</span>
                    <input className="mn-input" type="email" placeholder="seu@email.com"
                      value={forgotEmail} onChange={e=>setForgotEmail(e.target.value)} />
                  </div>
                </div>
                <button className="mn-btn-primary" onClick={handleForgot} disabled={btnLoading}>
                  {btnLoading ? 'Enviando...' : 'Enviar link de redefinição'}
                </button>
                <button className="mn-btn-ghost" onClick={() => switchTab('login')}>
                  ← Voltar ao login
                </button>
              </>
            )}

            {/* Social proof */}
            <div style={{display:'flex',alignItems:'center',justifyContent:'center',gap:14,
              marginTop:28,paddingTop:22,borderTop:'1px solid rgba(255,255,255,.07)'}}>
              <div style={{display:'flex'}}>
                {['G','R','A','F'].map((l,i)=>(
                  <div key={l} style={{width:26,height:26,borderRadius:'50%',
                    border:'2px solid #030508',
                    background:'linear-gradient(135deg,#1a6cff,#4d94ff)',
                    display:'flex',alignItems:'center',justifyContent:'center',
                    fontSize:10,fontWeight:800,marginLeft:i===0?0:-8}}>
                    {l}
                  </div>
                ))}
              </div>
              <p style={{fontSize:12,color:'rgba(255,255,255,.5)',lineHeight:1.5}}>
                <strong style={{color:'#fff'}}>+2.400 pessoas</strong> já controlam<br/>suas finanças com a Monetax
              </p>
            </div>
          </div>
        </div>
      </main>

      {/* Footer */}
      <footer style={{textAlign:'center',padding:20,fontSize:11,
        color:'rgba(255,255,255,.25)',position:'relative',zIndex:2}}>
        © 2026 Monetax ·{' '}
        <a href="/privacidade" className="mn-footer-a">Política de Privacidade</a> ·{' '}
        <a href="/termos" className="mn-footer-a">Termos de Uso</a> ·{' '}
        <a href="https://www.instagram.com/monetax.br/" target="_blank" rel="noopener noreferrer" className="mn-footer-a">@monetax.br</a> ·{' '}
        <a href="/?section=pricing" className="mn-footer-a">Ver planos e preços ↓</a>
      </footer>
    </div>
  )
}
